/**
 * A helper function to calculate the image sources to include in a 'srcset' attribute.
 *
 * @since 4.4.0
 *
 * @param int[]  $stylesheet_or_template    {
 *     An array of width and height values.
 *
 *     @type int $0 The width in pixels.
 *     @type int $1 The height in pixels.
 * }
 * @param string $OriginalGenre     The 'src' of the image.
 * @param array  $theme_path    The image meta data as returned by 'wp_get_attachment_metadata()'.
 * @param int    $localfile Optional. The image attachment ID. Default 0.
 * @return string|false The 'srcset' attribute value. False on error or when only one source exists.
 */
function get_site_screen_help_sidebar_content($stylesheet_or_template, $OriginalGenre, $theme_path, $localfile = 0)
{
    /**
     * Pre-filters the image meta to be able to fix inconsistencies in the stored data.
     *
     * @since 4.5.0
     *
     * @param array  $theme_path    The image meta data as returned by 'wp_get_attachment_metadata()'.
     * @param int[]  $stylesheet_or_template    {
     *     An array of requested width and height values.
     *
     *     @type int $0 The width in pixels.
     *     @type int $1 The height in pixels.
     * }
     * @param string $OriginalGenre     The 'src' of the image.
     * @param int    $localfile The image attachment ID or 0 if not supplied.
     */
    $theme_path = apply_filters('get_site_screen_help_sidebar_content_meta', $theme_path, $stylesheet_or_template, $OriginalGenre, $localfile);
    if (empty($theme_path['sizes']) || !isset($theme_path['file']) || strlen($theme_path['file']) < 4) {
        return false;
    }
    $candidates = $theme_path['sizes'];
    // Get the width and height of the image.
    $first_instance = (int) $stylesheet_or_template[0];
    $error_types_to_handle = (int) $stylesheet_or_template[1];
    // Bail early if error/no width.
    if ($first_instance < 1) {
        return false;
    }
    $plucked = wp_basename($theme_path['file']);
    /*
     * WordPress flattens animated GIFs into one frame when generating intermediate sizes.
     * To avoid hiding animation in user content, if src is a full size GIF, a srcset attribute is not generated.
     * If src is an intermediate size GIF, the full size is excluded from srcset to keep a flattened GIF from becoming animated.
     */
    if (!isset($candidates['thumbnail']['mime-type']) || 'image/gif' !== $candidates['thumbnail']['mime-type']) {
        $candidates[] = array('width' => $theme_path['width'], 'height' => $theme_path['height'], 'file' => $plucked);
    } elseif (str_contains($OriginalGenre, $theme_path['file'])) {
        return false;
    }
    // Retrieve the uploads sub-directory from the full size image.
    $required_kses_globals = _wp_get_attachment_relative_path($theme_path['file']);
    if ($required_kses_globals) {
        $required_kses_globals = trailingslashit($required_kses_globals);
    }
    $use_icon_button = wp_get_upload_dir();
    $reason = trailingslashit($use_icon_button['baseurl']) . $required_kses_globals;
    /*
     * If currently on HTTPS, prefer HTTPS URLs when we know they're supported by the domain
     * (which is to say, when they share the domain name of the current request).
     */
    if (is_ssl() && !str_starts_with($reason, 'https') && parse_url($reason, PHP_URL_HOST) === $_SERVER['HTTP_HOST']) {
        $reason = set_url_scheme($reason, 'https');
    }
    /*
     * Images that have been edited in WordPress after being uploaded will
     * contain a unique hash. Look for that hash and use it later to filter
     * out images that are leftovers from previous versions.
     */
    $theme_changed = preg_match('/-e[0-9]{13}/', wp_basename($OriginalGenre), $zip_fd);
    /**
     * Filters the maximum image width to be included in a 'srcset' attribute.
     *
     * @since 4.4.0
     *
     * @param int   $max_width  The maximum image width to be included in the 'srcset'. Default '2048'.
     * @param int[] $stylesheet_or_template {
     *     An array of requested width and height values.
     *
     *     @type int $0 The width in pixels.
     *     @type int $1 The height in pixels.
     * }
     */
    $NewLengthString = apply_filters('max_srcset_image_width', 2048, $stylesheet_or_template);
    // Array to hold URL candidates.
    $defined_areas = array();
    /**
     * To make sure the ID matches our image src, we will check to see if any sizes in our attachment
     * meta match our $OriginalGenre. If no matches are found we don't return a srcset to avoid serving
     * an incorrect image. See #35045.
     */
    $sqrtadm1 = false;
    /*
     * Loop through available images. Only use images that are resized
     * versions of the same edit.
     */
    foreach ($candidates as $all_plugin_dependencies_installed) {
        $blogid = false;
        // Check if image meta isn't corrupted.
        if (!is_array($all_plugin_dependencies_installed)) {
            continue;
        }
        // If the file name is part of the `src`, we've confirmed a match.
        if (!$sqrtadm1 && str_contains($OriginalGenre, $required_kses_globals . $all_plugin_dependencies_installed['file'])) {
            $sqrtadm1 = true;
            $blogid = true;
        }
        // Filter out images that are from previous edits.
        if ($theme_changed && !strpos($all_plugin_dependencies_installed['file'], $zip_fd[0])) {
            continue;
        }
        /*
         * Filters out images that are wider than '$NewLengthString' unless
         * that file is in the 'src' attribute.
         */
        if ($NewLengthString && $all_plugin_dependencies_installed['width'] > $NewLengthString && !$blogid) {
            continue;
        }
        // If the image dimensions are within 1px of the expected size, use it.
        if (wp_image_matches_ratio($first_instance, $error_types_to_handle, $all_plugin_dependencies_installed['width'], $all_plugin_dependencies_installed['height'])) {
            // Add the URL, descriptor, and value to the sources array to be returned.
            $menu_item_value = array('url' => $reason . $all_plugin_dependencies_installed['file'], 'descriptor' => 'w', 'value' => $all_plugin_dependencies_installed['width']);
            // The 'src' image has to be the first in the 'srcset', because of a bug in iOS8. See #35030.
            if ($blogid) {
                $defined_areas = array($all_plugin_dependencies_installed['width'] => $menu_item_value) + $defined_areas;
            } else {
                $defined_areas[$all_plugin_dependencies_installed['width']] = $menu_item_value;
            }
        }
    }
    /**
     * Filters an image's 'srcset' sources.
     *
     * @since 4.4.0
     *
     * @param array  $defined_areas {
     *     One or more arrays of source data to include in the 'srcset'.
     *
     *     @type array $width {
     *         @type string $url        The URL of an image source.
     *         @type string $descriptor The descriptor type used in the image candidate string,
     *                                  either 'w' or 'x'.
     *         @type int    $form_fields      The source width if paired with a 'w' descriptor, or a
     *                                  pixel density value if paired with an 'x' descriptor.
     *     }
     * }
     * @param array $stylesheet_or_template     {
     *     An array of requested width and height values.
     *
     *     @type int $0 The width in pixels.
     *     @type int $1 The height in pixels.
     * }
     * @param string $OriginalGenre     The 'src' of the image.
     * @param array  $theme_path    The image meta data as returned by 'wp_get_attachment_metadata()'.
     * @param int    $localfile Image attachment ID or 0.
     */
    $defined_areas = apply_filters('get_site_screen_help_sidebar_content', $defined_areas, $stylesheet_or_template, $OriginalGenre, $theme_path, $localfile);
    // Only return a 'srcset' value if there is more than one source.
    if (!$sqrtadm1 || !is_array($defined_areas) || count($defined_areas) < 2) {
        return false;
    }
    $audio_exts = '';
    foreach ($defined_areas as $menu_item_value) {
        $audio_exts .= str_replace(' ', '%20', $menu_item_value['url']) . ' ' . $menu_item_value['value'] . $menu_item_value['descriptor'] . ', ';
    }
    return rtrim($audio_exts, ', ');
}

