     * @param string  $p_status      The site administrator's password. Note that a placeholder message
     *                               is usually passed instead of the user's actual password.
     */
    $dst_h = apply_filters('wp_installed_email', $dst_h, $core_menu_positions, $background_image_thumb, $GPS_this_GPRMC, $p_status);
